// Extend a basic PowerNode or PowerGenerator class depending on your choice.
// We use PowerNode here to utilize its native neighborhood power-conduction logic.
const deepWaterPowerBlock = extend(PowerNode, "deep-water-transmitter", {
    // Block Configurations
    size: 2,
    health: 400,
    
    // Power behaviors
    outputsPower: true,     // Allows the block to supply power
    consumesPower: false,   // Does not consume power itself
    
    // CRITICAL: Prevents power nodes from creating laser links to this block
    connectedPower: false,  //
    
    // Allows the block to naturally touch and transmit power to adjacent touching blocks
    conductivePower: true,  //
    
    // Placement rules for Deep Water
    // Forces the block to only be buildable on deep water/liquids (like the mechanical pump)
    floating: true,
    placeableLiquid: true,
});

// Configure where it appears and what it costs
deepWaterPowerBlock.category = Category.power;
deepWaterPowerBlock.buildVisibility = BuildVisibility.shown;
deepWaterPowerBlock.requirements = ItemStack.with(
    Items.silicon, 40,
    Items.metaglass, 20,
    Items.lead, 50
);
